SEXP stringToRaw(std::string x) {
  SEXP y;
  PROTECT(y = allocVector(RAWSXP, x.length()));
  memcpy(RAW(y), x.data(), x.length());
  UNPROTECT(1);
  return y;
}

How do i do this with Rcpp? Say i want to return a Rcpp::RawVector?
